// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

// Package quota implements a PolicyQuotaController that enforces per-namespace
// limits on the number of CiliumNetworkPolicy resources, preventing policy
// sprawl in multi-tenant clusters.
package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController watches CiliumNetworkPolicy resources and enforces
// per-namespace limits to prevent policy sprawl in multi-tenant clusters.
type PolicyQuotaController struct {
	// maxPerNamespace is the maximum number of CiliumNetworkPolicy resources
	// allowed per namespace. 0 means no limit.
	maxPerNamespace int

	// ciliumNetworkPolicies is the resource watcher for CiliumNetworkPolicy.
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]

	// mu protects namespaceCounts.
	mu sync.RWMutex

	// namespaceCounts maps namespace name to the number of CiliumNetworkPolicy
	// resources currently in that namespace.
	namespaceCounts map[string]int

	log logrus.FieldLogger
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
//
// Parameters:
//   - ciliumNetworkPolicies: resource watcher for CiliumNetworkPolicy objects
//   - maxPerNamespace: maximum number of policies allowed per namespace (0 = unlimited)
func NewPolicyQuotaController(
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		maxPerNamespace:       maxPerNamespace,
		ciliumNetworkPolicies: ciliumNetworkPolicies,
		namespaceCounts:       make(map[string]int),
		log:                   log,
	}
}

// Run starts the PolicyQuotaController loop. It processes CiliumNetworkPolicy
// events from the resource watcher and maintains per-namespace counts.
// Run blocks until ctx is cancelled.
func (c *PolicyQuotaController) Run(ctx context.Context) {
	c.log.Info("Starting PolicyQuotaController")

	events := c.ciliumNetworkPolicies.Events(ctx)
	for {
		select {
		case <-ctx.Done():
			c.log.Info("Stopping PolicyQuotaController")
			return
		case event, ok := <-events:
			if !ok {
				c.log.Info("PolicyQuotaController event channel closed")
				return
			}

			switch event.Kind {
			case resource.Sync:
				c.log.Debug("PolicyQuotaController: initial sync complete")
				event.Done(nil)

			case resource.Upsert:
				ns := event.Object.GetNamespace()
				key := event.Key

				c.mu.Lock()
				// Check if this is a new policy (not an update to existing).
				// resource.Key includes namespace/name so we track by key.
				// For simplicity we track by namespace: on upsert we always
				// increment if this is a new key. We use the store to get
				// accurate counts.
				_ = key
				_ = ns
				// Rebuild counts from current store to stay accurate.
				c.rebuildCountsLocked(ctx)
				c.mu.Unlock()

				event.Done(nil)

			case resource.Delete:
				c.mu.Lock()
				c.rebuildCountsLocked(ctx)
				c.mu.Unlock()

				event.Done(nil)
			}
		}
	}
}

// rebuildCountsLocked rebuilds the namespaceCounts map from the current store.
// Must be called with c.mu held.
func (c *PolicyQuotaController) rebuildCountsLocked(ctx context.Context) {
	store, err := c.ciliumNetworkPolicies.Store(ctx)
	if err != nil {
		c.log.WithError(err).Warning("Failed to get CiliumNetworkPolicy store")
		return
	}

	counts := make(map[string]int)
	for _, obj := range store.List() {
		ns := obj.GetNamespace()
		counts[ns]++
	}
	c.namespaceCounts = counts
}

// CheckQuota returns an error if the namespace has exceeded the configured
// maximum number of CiliumNetworkPolicy resources. If maxPerNamespace is 0
// (unlimited), CheckQuota always returns nil.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	if c.maxPerNamespace == 0 {
		return nil
	}

	c.mu.RLock()
	count := c.namespaceCounts[namespace]
	c.mu.RUnlock()

	if count >= c.maxPerNamespace {
		return fmt.Errorf(
			"namespace %q has reached the CiliumNetworkPolicy quota: %d/%d policies",
			namespace, count, c.maxPerNamespace,
		)
	}
	return nil
}

// NamespaceCount returns the current number of CiliumNetworkPolicy resources
// in the given namespace. This is safe for concurrent use.
func (c *PolicyQuotaController) NamespaceCount(namespace string) int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.namespaceCounts[namespace]
}

// SetNamespaceCount directly sets the policy count for a namespace.
// This is intended for testing purposes only.
func (c *PolicyQuotaController) SetNamespaceCount(namespace string, count int) {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.namespaceCounts[namespace] = count
}

