func TestCheckQuota_UnderLimit(t *testing.T) {
	c := &PolicyQuotaController{
		maxPerNamespace: 5,
		namespaceCounts: map[string]int{
			"default": 3,
		},
	}

	if err := c.CheckQuota("default"); err != nil {
		t.Errorf("expected no error when under quota, got: %v", err)
	}
}

// TestCheckQuota_AtLimit verifies that CheckQuota returns an error when the
// namespace has exactly reached the configured limit.
func TestCheckQuota_AtLimit(t *testing.T) {
	c := &PolicyQuotaController{
		maxPerNamespace: 5,
		namespaceCounts: map[string]int{
			"default": 5,
		},
	}

	if err := c.CheckQuota("default"); err == nil {
		t.Error("expected error when at quota limit, got nil")
	}
}

// TestCheckQuota_OverLimit verifies that CheckQuota returns an error when the
// namespace has exceeded the configured limit.
func TestCheckQuota_OverLimit(t *testing.T) {
	c := &PolicyQuotaController{
		maxPerNamespace: 5,
		namespaceCounts: map[string]int{
			"default": 10,
		},
	}

	if err := c.CheckQuota("default"); err == nil {
		t.Error("expected error when over quota limit, got nil")
	}
}

// TestCheckQuota_EmptyNamespace verifies that CheckQuota returns nil for a
// namespace with no policies (not in the map).
func TestCheckQuota_EmptyNamespace(t *testing.T) {
	c := &PolicyQuotaController{
		maxPerNamespace: 5,
		namespaceCounts: map[string]int{},
	}

	if err := c.CheckQuota("kube-system"); err != nil {
		t.Errorf("expected no error for empty namespace, got: %v", err)
	}
}

// TestCheckQuota_MultipleNamespaces verifies that quota is tracked independently
// per namespace.
func TestCheckQuota_MultipleNamespaces(t *testing.T) {
	c := &PolicyQuotaController{
		maxPerNamespace: 3,
		namespaceCounts: map[string]int{
			"ns-a": 3,
			"ns-b": 2,
			"ns-c": 0,
		},
	}

	// ns-a is at the limit
	if err := c.CheckQuota("ns-a"); err == nil {
		t.Error("expected error for ns-a which is at limit")
	}

	// ns-b is under the limit
	if err := c.CheckQuota("ns-b"); err != nil {
		t.Errorf("expected no error for ns-b which is under limit, got: %v", err)
	}

	// ns-c is empty
	if err := c.CheckQuota("ns-c"); err != nil {
		t.Errorf("expected no error for ns-c which is empty, got: %v", err)
	}
}

