func TestNamespaceCount(t *testing.T) {
	c := &PolicyQuotaController{
		maxPerNamespace: 10,
		namespaceCounts: map[string]int{
			"default": 4,
		},
	}

	if got := c.NamespaceCount("default"); got != 4 {
		t.Errorf("expected 4, got %d", got)
	}

	if got := c.NamespaceCount("nonexistent"); got != 0 {
		t.Errorf("expected 0 for missing namespace, got %d", got)
	}
}

