func TestNewPolicyQuotaController(t *testing.T) {
	c := &PolicyQuotaController{
		maxPerNamespace: 10,
		namespaceCounts: make(map[string]int),
	}

	if c.maxPerNamespace != 10 {
		t.Errorf("expected maxPerNamespace=10, got %d", c.maxPerNamespace)
	}

	if c.namespaceCounts == nil {
		t.Error("expected namespaceCounts to be initialized")
	}
}

